import 'package:http/http.dart' as http;
import 'dart:convert';

void main() async {
  try {
    // Connect to cloud API using HTTPS
    var cloudResponse = await http.get(Uri.parse('https://api.example.com/data'));
    if (cloudResponse.statusCode == 200) {
      print('Cloud data: ${jsonDecode(cloudResponse.body)}');
    } else {
      print('Failed to load cloud data: ${cloudResponse.statusCode}');
    }

    // Connect to local IoT device using HTTP
    var iotResponse = await http.get(Uri.parse('http://192.168.x.x/data'));
    if (iotResponse.statusCode == 200) {
      print('IoT data: ${jsonDecode(iotResponse.body)}');
    } else {
      print('Failed to load IoT data: ${iotResponse.statusCode}');
    }
  } catch (e) {
    print('Error connecting to the server: $e');
  }
}